def skew_symmetric_matrix_from_axis_angle(axis_angle: torch.Tensor) -> torch.Tensor:

    skew_mat = torch.zeros([*axis_angle.shape[:-1], 3, 3])
    skew_mat[..., 0, 1], skew_mat[..., 0, 2], skew_mat[..., 1, 2] = (
        -axis_angle[..., 2],
